class Solution:
    def toGoatLatin(self, sentence):
        vowels = set('aeiouAEIOU')
        out = []
        words = sentence.split(' ')
        for index in range(len(words)):
            w = words[index]
            if w[0] in vowels:
                core = w
            else:
                core = w[1:] + w[0]
            core = core + 'ma'
            core = core + 'a' * (index + 1)
            out.append(core)
        return ' '.join(out)

