class Solution:
    def toGoatLatin(self, sentence):
        vowels = set('aeiouAEIOU')
        result = []
        for i, w in enumerate(sentence.split(' '), start=1):
            if w[0] not in vowels:
                w = w[1:] + w[0]
            result.append(w + 'ma' + 'a' * i)
        return ' '.join(result)

