var toGoatLatin = function(sentence) {
    const vowels = new Set(['a','e','i','o','u','A','E','I','O','U']);
    const words = sentence.split(' ');
    const result = [];
    for (let i = 0; i < words.length; i++) {
        let w = words[i];
        if (!vowels.has(w[0])) {
            w = w.slice(1) + w[0];
        }
        result.push(w + 'ma' + 'a'.repeat(i + 1));
    }
    return result.join(' ');
};
